-- Add new schema named "config"
CREATE SCHEMA IF NOT EXISTS "config";
-- Create "auth_endpoint_patterns" table
CREATE TABLE "config"."auth_endpoint_patterns" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "pattern_type" character varying NOT NULL,
  "match_mode" character varying NOT NULL,
  "pattern" character varying NOT NULL,
  "source" character varying NOT NULL DEFAULT 'custom',
  "description" character varying NULL,
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "configauthendpointpattern_is_active" to table: "auth_endpoint_patterns"
CREATE INDEX "configauthendpointpattern_is_active" ON "config"."auth_endpoint_patterns" ("is_active");
-- Create index "configauthendpointpattern_pattern_type" to table: "auth_endpoint_patterns"
CREATE INDEX "configauthendpointpattern_pattern_type" ON "config"."auth_endpoint_patterns" ("pattern_type");
-- Create index "configauthendpointpattern_pattern_type_pattern" to table: "auth_endpoint_patterns"
CREATE UNIQUE INDEX "configauthendpointpattern_pattern_type_pattern" ON "config"."auth_endpoint_patterns" ("pattern_type", "pattern");
-- Create "hosting_indicators" table
CREATE TABLE "config"."hosting_indicators" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "indicator_type" character varying NOT NULL,
  "value" character varying NOT NULL,
  "description" character varying NULL,
  "country" character varying NULL,
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "confighostingindicator_country" to table: "hosting_indicators"
CREATE INDEX "confighostingindicator_country" ON "config"."hosting_indicators" ("country");
-- Create index "confighostingindicator_indicator_type_is_active" to table: "hosting_indicators"
CREATE INDEX "confighostingindicator_indicator_type_is_active" ON "config"."hosting_indicators" ("indicator_type", "is_active");
-- Create index "confighostingindicator_indicator_type_value" to table: "hosting_indicators"
CREATE UNIQUE INDEX "confighostingindicator_indicator_type_value" ON "config"."hosting_indicators" ("indicator_type", "value");
-- Create "httpmonitor_rules" table
CREATE TABLE "config"."httpmonitor_rules" (
  "rule_id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "rule_key" character varying NOT NULL,
  "anomaly_type" character varying NOT NULL,
  "severity" character varying NOT NULL,
  "category" character varying NOT NULL,
  "name" character varying NOT NULL,
  "description" character varying NOT NULL,
  "baseline" character varying NULL,
  "thresholds_json" jsonb NULL,
  "status" character varying NOT NULL DEFAULT 'live',
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("rule_id")
);
-- Create index "confighttpmonitorrule_anomaly_type" to table: "httpmonitor_rules"
CREATE INDEX "confighttpmonitorrule_anomaly_type" ON "config"."httpmonitor_rules" ("anomaly_type");
-- Create index "confighttpmonitorrule_category" to table: "httpmonitor_rules"
CREATE INDEX "confighttpmonitorrule_category" ON "config"."httpmonitor_rules" ("category");
-- Create index "confighttpmonitorrule_status" to table: "httpmonitor_rules"
CREATE INDEX "confighttpmonitorrule_status" ON "config"."httpmonitor_rules" ("status");
-- Create index "httpmonitor_rules_rule_key_key" to table: "httpmonitor_rules"
CREATE UNIQUE INDEX "httpmonitor_rules_rule_key_key" ON "config"."httpmonitor_rules" ("rule_key");
-- Create "library_uas" table
CREATE TABLE "config"."library_uas" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
