-- Create index "configrpmcorerepo_is_active" to table: "rpm_core_repos"
CREATE INDEX "configrpmcorerepo_is_active" ON "config"."rpm_core_repos" ("is_active");
-- Create index "rpm_core_repos_repo_name_key" to table: "rpm_core_repos"
